package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  private AccessibleObject accessibleObjectMock;
  private Object targetObject;
  private Object accessCheckerMock;
  private Class<?> accessCheckerClass;

  @BeforeEach
  void setUp() throws Exception {
    accessibleObjectMock = mock(AccessibleObject.class);
    targetObject = new Object();

    accessCheckerClass = Class.forName("com.google.gson.internal.ReflectionAccessFilterHelper$AccessChecker");
    accessCheckerMock = mock(accessCheckerClass);

    Field instanceField = accessCheckerClass.getDeclaredField("INSTANCE");
    instanceField.setAccessible(true);

    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(instanceField, instanceField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    instanceField.set(null, accessCheckerMock);
  }

  @Test
  void testCanAccess_returnsTrue_whenAccessCheckerReturnsTrue() throws Exception {
    // Create a dynamic proxy that implements the same interfaces as accessCheckerMock, or subclass it
    // Since AccessChecker is a class, not interface, we cannot use Proxy directly.
    // Instead, use a subclass mock via Mockito spy or a custom InvocationHandler on the mock's interfaces.

    // Find interfaces implemented by AccessChecker (if any)
    Class<?>[] interfaces = accessCheckerClass.getInterfaces();
    if (interfaces.length == 0) {
      // No interfaces, fallback to using Mockito spy and override canAccess method via reflection
      // Use Mockito's doReturn on the mock's canAccess method

      Method canAccessMethod = accessCheckerClass.getMethod("canAccess", AccessibleObject.class, Object.class);
      // Use Mockito to stub the canAccess method on the mock
      // For this, use Mockito's doReturn on the mock's method via reflection

      // Use Mockito's doAnswer with reflection proxy to stub canAccess method on the mock:
      doReturn(true).when(accessCheckerMock).getClass()
          .getMethod("canAccess", AccessibleObject.class, Object.class)
          .invoke(accessCheckerMock, accessibleObjectMock, targetObject);

      // However, above won't work because invoke is final and can't be stubbed directly.
      // Instead, use reflection to create a subclass mock with Mockito:
      // But since accessCheckerMock is already a mock, we can stub canAccess method directly via Mockito:

      // Use Mockito's when with reflection:
      when(canAccessMethod.invoke(accessCheckerMock, accessibleObjectMock, targetObject)).thenReturn(true);
      // This won't work either because invoke is final.

      // Instead, use Mockito's doAnswer on the mock's canAccess method by creating a helper interface:

      // Create a helper interface with canAccess method signature
      interface AccessCheckerInterface {
        boolean canAccess(AccessibleObject ao, Object o);
      }

      // Create a proxy implementing AccessCheckerInterface that delegates to accessCheckerMock
      AccessCheckerInterface proxy = (AccessCheckerInterface) Proxy.newProxyInstance(
          AccessCheckerInterface.class.getClassLoader(),
          new Class<?>[] { AccessCheckerInterface.class },
          new InvocationHandler() {
            @Override
            public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
              if ("canAccess".equals(method.getName())
                  && args.length == 2
                  && args[0] == accessibleObjectMock
                  && args[1] == targetObject) {
                return true;
              }
              // Delegate to original mock via reflection
              Method m = accessCheckerClass.getMethod("canAccess", AccessibleObject.class, Object.class);
              return m.invoke(accessCheckerMock, args);
            }
          });

      // Set INSTANCE field to proxy (cast to Object)
      Field instanceField = accessCheckerClass.getDeclaredField("INSTANCE");
      instanceField.setAccessible(true);
      instanceField.set(null, proxy);

      boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
      assertTrue(result);
      return;
    }

    // If AccessChecker implements interfaces, create a Proxy with those interfaces:
    Object proxy = Proxy.newProxyInstance(
        accessCheckerClass.getClassLoader(),
        interfaces,
        (proxyObj, method, args) -> {
          if ("canAccess".equals(method.getName())
              && args.length == 2
              && args[0] == accessibleObjectMock
              && args[1] == targetObject) {
            return true;
          }
          return method.invoke(accessCheckerMock, args);
        });

    Field instanceField = accessCheckerClass.getDeclaredField("INSTANCE");
    instanceField.setAccessible(true);
    instanceField.set(null, proxy);

    boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
    assertTrue(result);
  }

  @Test
  void testCanAccess_returnsFalse_whenAccessCheckerReturnsFalse() throws Exception {
    // Same strategy as above for false return

    interface AccessCheckerInterface {
      boolean canAccess(AccessibleObject ao, Object o);
    }

    AccessCheckerInterface proxy = (AccessCheckerInterface) Proxy.newProxyInstance(
        AccessCheckerInterface.class.getClassLoader(),
        new Class<?>[] { AccessCheckerInterface.class },
        new InvocationHandler() {
          @Override
          public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
            if ("canAccess".equals(method.getName())
                && args.length == 2
                && args[0] == accessibleObjectMock
                && args[1] == targetObject) {
              return false;
            }
            Method m = accessCheckerClass.getMethod("canAccess", AccessibleObject.class, Object.class);
            return m.invoke(accessCheckerMock, args);
          }
        });

    Field instanceField = accessCheckerClass.getDeclaredField("INSTANCE");
    instanceField.setAccessible(true);
    instanceField.set(null, proxy);

    boolean result = ReflectionAccessFilterHelper.canAccess(accessibleObjectMock, targetObject);
    assertFalse(result);
  }

  @Test
  void testPrivateConstructor() throws Exception {
    var constructor = ReflectionAccessFilterHelper.class.getDeclaredConstructor();
    constructor.setAccessible(true);
    Object instance = constructor.newInstance();
    assertNotNull(instance);
  }
}
